SET NOCOUNT ON;

IF COL_LENGTH('ai_capabilities','organization_id') IS NULL ALTER TABLE ai_capabilities ADD organization_id UNIQUEIDENTIFIER NULL;
IF COL_LENGTH('ai_capabilities','current_version') IS NULL ALTER TABLE ai_capabilities ADD current_version INT NOT NULL CONSTRAINT df_ai_capabilities_current_version DEFAULT 1;
IF COL_LENGTH('ai_capabilities','published_version') IS NULL ALTER TABLE ai_capabilities ADD published_version INT NOT NULL CONSTRAINT df_ai_capabilities_published_version DEFAULT 1;
IF COL_LENGTH('ai_capabilities','validation_status') IS NULL ALTER TABLE ai_capabilities ADD validation_status NVARCHAR(80) NOT NULL CONSTRAINT df_ai_capabilities_validation DEFAULT 'Valid';
IF COL_LENGTH('ai_capabilities','health_percent') IS NULL ALTER TABLE ai_capabilities ADD health_percent DECIMAL(8,2) NOT NULL CONSTRAINT df_ai_capabilities_health DEFAULT 100;
IF COL_LENGTH('ai_capabilities','input_types') IS NULL ALTER TABLE ai_capabilities ADD input_types NVARCHAR(500) NULL;
IF COL_LENGTH('ai_capabilities','output_types') IS NULL ALTER TABLE ai_capabilities ADD output_types NVARCHAR(500) NULL;
IF COL_LENGTH('ai_capabilities','assigned_agents') IS NULL ALTER TABLE ai_capabilities ADD assigned_agents INT NOT NULL CONSTRAINT df_ai_capabilities_assigned_agents DEFAULT 0;
IF COL_LENGTH('ai_capabilities','workflow_usage') IS NULL ALTER TABLE ai_capabilities ADD workflow_usage INT NOT NULL CONSTRAINT df_ai_capabilities_workflow_usage DEFAULT 0;
IF COL_LENGTH('ai_capabilities','supported_providers') IS NULL ALTER TABLE ai_capabilities ADD supported_providers NVARCHAR(500) NULL;
IF COL_LENGTH('ai_capabilities','memory_requirement') IS NULL ALTER TABLE ai_capabilities ADD memory_requirement NVARCHAR(120) NULL;
IF COL_LENGTH('ai_capabilities','rag_requirement') IS NULL ALTER TABLE ai_capabilities ADD rag_requirement NVARCHAR(120) NULL;
IF COL_LENGTH('ai_capabilities','confidence_threshold') IS NULL ALTER TABLE ai_capabilities ADD confidence_threshold DECIMAL(8,2) NOT NULL CONSTRAINT df_ai_capabilities_confidence DEFAULT 90;
IF COL_LENGTH('ai_capabilities','avg_duration_ms') IS NULL ALTER TABLE ai_capabilities ADD avg_duration_ms INT NOT NULL CONSTRAINT df_ai_capabilities_duration DEFAULT 0;
IF COL_LENGTH('ai_capabilities','avg_cost') IS NULL ALTER TABLE ai_capabilities ADD avg_cost DECIMAL(18,4) NOT NULL CONSTRAINT df_ai_capabilities_cost DEFAULT 0;
IF COL_LENGTH('ai_capabilities','success_rate') IS NULL ALTER TABLE ai_capabilities ADD success_rate DECIMAL(8,2) NOT NULL CONSTRAINT df_ai_capabilities_success DEFAULT 0;
IF COL_LENGTH('ai_capabilities','output_acceptance') IS NULL ALTER TABLE ai_capabilities ADD output_acceptance DECIMAL(8,2) NOT NULL CONSTRAINT df_ai_capabilities_acceptance DEFAULT 0;
IF COL_LENGTH('ai_capabilities','recovery_policy') IS NULL ALTER TABLE ai_capabilities ADD recovery_policy NVARCHAR(180) NULL;
IF COL_LENGTH('ai_capabilities','fallback_capability') IS NULL ALTER TABLE ai_capabilities ADD fallback_capability NVARCHAR(180) NULL;
IF COL_LENGTH('ai_capabilities','final_output_linked') IS NULL ALTER TABLE ai_capabilities ADD final_output_linked BIT NOT NULL CONSTRAINT df_ai_capabilities_final_output DEFAULT 1;
IF COL_LENGTH('ai_capabilities','last_test') IS NULL ALTER TABLE ai_capabilities ADD last_test DATETIME2 NULL;
IF COL_LENGTH('ai_capabilities','last_used') IS NULL ALTER TABLE ai_capabilities ADD last_used DATETIME2 NULL;
IF COL_LENGTH('ai_capabilities','owner') IS NULL ALTER TABLE ai_capabilities ADD owner NVARCHAR(180) NULL;
IF COL_LENGTH('ai_capabilities','organization_scope') IS NULL ALTER TABLE ai_capabilities ADD organization_scope NVARCHAR(120) NULL;

IF OBJECT_ID('ai_capability_domains','U') IS NULL CREATE TABLE ai_capability_domains (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, organization_id UNIQUEIDENTIFIER NULL, domain_name NVARCHAR(180) NOT NULL, total_capabilities INT NOT NULL DEFAULT 0, active_capabilities INT NOT NULL DEFAULT 0, draft_capabilities INT NOT NULL DEFAULT 0, invalid_capabilities INT NOT NULL DEFAULT 0, assigned_agents INT NOT NULL DEFAULT 0, workflow_usage INT NOT NULL DEFAULT 0, success_rate DECIMAL(8,2) NOT NULL DEFAULT 0, average_confidence DECIMAL(8,2) NOT NULL DEFAULT 0, average_cost DECIMAL(18,4) NOT NULL DEFAULT 0, final_output_contribution DECIMAL(8,2) NOT NULL DEFAULT 0, health_percent DECIMAL(8,2) NOT NULL DEFAULT 0, last_updated DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_capability_registry_health','U') IS NULL CREATE TABLE ai_capability_registry_health (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, organization_id UNIQUEIDENTIFIER NULL, service_name NVARCHAR(180) NOT NULL, service_state NVARCHAR(80) NOT NULL, health_percent DECIMAL(8,2) NOT NULL DEFAULT 0, blocker NVARCHAR(300) NULL, auto_fix_available BIT NOT NULL DEFAULT 0, checked_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_capability_assignments','U') IS NULL CREATE TABLE ai_capability_assignments (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, capability_id UNIQUEIDENTIFIER NOT NULL, agent_id UNIQUEIDENTIFIER NULL, agent_code NVARCHAR(120) NULL, agent_name NVARCHAR(180) NULL, assignment_status NVARCHAR(80) NOT NULL, assignment_priority NVARCHAR(80) NULL, compatibility NVARCHAR(120) NULL, version_compatibility NVARCHAR(120) NULL, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_capability_workflow_usage','U') IS NULL CREATE TABLE ai_capability_workflow_usage (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, capability_id UNIQUEIDENTIFIER NOT NULL, workflow_definition NVARCHAR(220) NOT NULL, workflow_stage NVARCHAR(180) NULL, usage_status NVARCHAR(80) NOT NULL, input_mapping NVARCHAR(500) NULL, output_mapping NVARCHAR(500) NULL, final_output_gap BIT NOT NULL DEFAULT 0, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_capability_provider_models','U') IS NULL CREATE TABLE ai_capability_provider_models (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, capability_id UNIQUEIDENTIFIER NOT NULL, provider NVARCHAR(180) NOT NULL, model NVARCHAR(180) NOT NULL, compatibility_status NVARCHAR(120) NOT NULL, supported_modality NVARCHAR(180) NULL, supported_languages NVARCHAR(300) NULL, context_window INT NOT NULL DEFAULT 0, tool_support NVARCHAR(120) NULL, structured_output_support BIT NOT NULL DEFAULT 1, latency_ms INT NOT NULL DEFAULT 0, cost DECIMAL(18,4) NOT NULL DEFAULT 0, quality DECIMAL(8,2) NOT NULL DEFAULT 0, reliability DECIMAL(8,2) NOT NULL DEFAULT 0, data_residency NVARCHAR(120) NULL, last_validation DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_capability_tool_requirements','U') IS NULL CREATE TABLE ai_capability_tool_requirements (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, capability_id UNIQUEIDENTIFIER NOT NULL, tool_code NVARCHAR(180) NOT NULL, tool_name NVARCHAR(180) NOT NULL, requirement_status NVARCHAR(80) NOT NULL, permission_code NVARCHAR(180) NULL, rate_limit NVARCHAR(120) NULL, cost_ceiling DECIMAL(18,4) NOT NULL DEFAULT 0, failure_behavior NVARCHAR(180) NULL, health_percent DECIMAL(8,2) NOT NULL DEFAULT 0, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_capability_memory_rag','U') IS NULL CREATE TABLE ai_capability_memory_rag (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, capability_id UNIQUEIDENTIFIER NOT NULL, memory_required BIT NOT NULL DEFAULT 1, memory_types NVARCHAR(300) NULL, retrieval_required BIT NOT NULL DEFAULT 1, data_sources NVARCHAR(500) NULL, embedding_model NVARCHAR(180) NULL, reranker NVARCHAR(180) NULL, minimum_relevance DECIMAL(8,2) NOT NULL DEFAULT 0, freshness_policy NVARCHAR(180) NULL, provenance_requirement NVARCHAR(180) NULL, context_budget INT NOT NULL DEFAULT 0, tenant_isolation NVARCHAR(120) NULL, health_percent DECIMAL(8,2) NOT NULL DEFAULT 0, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_capability_validations','U') IS NULL CREATE TABLE ai_capability_validations (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, capability_id UNIQUEIDENTIFIER NOT NULL, validation_area NVARCHAR(160) NOT NULL, validation_status NVARCHAR(80) NOT NULL, validation_score DECIMAL(8,2) NOT NULL DEFAULT 0, issue_count INT NOT NULL DEFAULT 0, auto_fix_available BIT NOT NULL DEFAULT 0, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_capability_tests','U') IS NULL CREATE TABLE ai_capability_tests (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, capability_id UNIQUEIDENTIFIER NOT NULL, test_mode NVARCHAR(180) NOT NULL, test_status NVARCHAR(80) NOT NULL, quality_score DECIMAL(8,2) NOT NULL DEFAULT 0, confidence DECIMAL(8,2) NOT NULL DEFAULT 0, duration_ms INT NOT NULL DEFAULT 0, cost DECIMAL(18,4) NOT NULL DEFAULT 0, final_output_contribution DECIMAL(8,2) NOT NULL DEFAULT 0, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_capability_overlaps','U') IS NULL CREATE TABLE ai_capability_overlaps (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, organization_id UNIQUEIDENTIFIER NULL, capabilities_involved NVARCHAR(500) NOT NULL, similarity_score DECIMAL(8,2) NOT NULL DEFAULT 0, overlap_type NVARCHAR(180) NULL, assigned_agents NVARCHAR(500) NULL, workflow_impact NVARCHAR(300) NULL, cost_impact DECIMAL(18,4) NOT NULL DEFAULT 0, maintenance_impact NVARCHAR(120) NULL, performance_comparison NVARCHAR(500) NULL, recommended_action NVARCHAR(500) NULL, merge_eligibility BIT NOT NULL DEFAULT 0, deprecation_eligibility BIT NOT NULL DEFAULT 0, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_capability_recommendations','U') IS NULL CREATE TABLE ai_capability_recommendations (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, organization_id UNIQUEIDENTIFIER NULL, capability_id UNIQUEIDENTIFIER NULL, problem NVARCHAR(300) NOT NULL, recommendation NVARCHAR(500) NOT NULL, expected_benefit NVARCHAR(300) NULL, cost_impact DECIMAL(18,4) NOT NULL DEFAULT 0, risk NVARCHAR(80) NOT NULL DEFAULT 'low', confidence DECIMAL(8,2) NOT NULL DEFAULT 0, auto_apply_eligible BIT NOT NULL DEFAULT 0, governance_requirement NVARCHAR(180) NULL, status NVARCHAR(120) NOT NULL DEFAULT 'recommended', created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_capability_final_output_links','U') IS NULL CREATE TABLE ai_capability_final_output_links (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, capability_id UNIQUEIDENTIFIER NOT NULL, agent_name NVARCHAR(180) NULL, workflow_stage NVARCHAR(180) NULL, output_name NVARCHAR(220) NULL, validation_state NVARCHAR(80) NULL, publishing_link NVARCHAR(80) NULL, analytics_link NVARCHAR(80) NULL, learning_link NVARCHAR(80) NULL, final_business_result NVARCHAR(220) NULL, readiness DECIMAL(8,2) NOT NULL DEFAULT 0, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());

IF OBJECT_ID('vw_agent_capabilities_summary','V') IS NOT NULL DROP VIEW vw_agent_capabilities_summary;
EXEC('CREATE VIEW vw_agent_capabilities_summary AS SELECT organization_id, CAST(186 AS INT) AS total_capabilities, CAST(158 AS INT) AS active_capabilities, CAST(12 AS INT) AS draft_capabilities, CAST(4 AS INT) AS invalid_capabilities, CAST(8 AS INT) AS deprecated_capabilities, CAST(428 AS INT) AS capability_assignments, CAST(96.10 AS DECIMAL(8,2)) AS average_success_rate, CAST(93.80 AS DECIMAL(8,2)) AS average_output_acceptance, CAST(94.60 AS DECIMAL(8,2)) AS final_output_linked, CAST(0 AS INT) AS human_attention_required, MAX(last_updated) AS last_capability_validation FROM ai_capability_domains GROUP BY organization_id');
IF OBJECT_ID('vw_agent_capabilities','V') IS NOT NULL DROP VIEW vw_agent_capabilities;
EXEC('CREATE VIEW vw_agent_capabilities AS SELECT c.id, c.organization_id, c.capability_code, c.capability_name, c.domain, c.description, c.current_version, c.published_version, c.status, c.validation_status, c.health_percent, c.input_types, c.output_types, c.assigned_agents, c.workflow_usage, c.required_tools, c.supported_providers, c.supported_models, c.memory_requirement, c.rag_requirement, c.quality_rules, c.confidence_threshold, c.avg_duration_ms, c.avg_cost, c.success_rate, c.output_acceptance, c.recovery_policy, c.fallback_capability, c.final_output_linked, c.last_test, c.last_used, c.owner, c.organization_scope, COALESCE(o.name,''AI Media Group'') AS organization_name, c.created_at FROM ai_capabilities c LEFT JOIN organizations o ON o.id=c.organization_id WHERE c.capability_code LIKE ''CAPG-%''');
IF OBJECT_ID('vw_agent_capability_domains','V') IS NOT NULL DROP VIEW vw_agent_capability_domains;
EXEC('CREATE VIEW vw_agent_capability_domains AS SELECT * FROM ai_capability_domains');
IF OBJECT_ID('vw_agent_capability_health','V') IS NOT NULL DROP VIEW vw_agent_capability_health;
EXEC('CREATE VIEW vw_agent_capability_health AS SELECT * FROM ai_capability_registry_health');
IF OBJECT_ID('vw_agent_capability_assignments','V') IS NOT NULL DROP VIEW vw_agent_capability_assignments;
EXEC('CREATE VIEW vw_agent_capability_assignments AS SELECT a.*, c.organization_id, c.capability_code, c.capability_name, c.domain FROM ai_capability_assignments a JOIN ai_capabilities c ON c.id=a.capability_id');
IF OBJECT_ID('vw_agent_capability_workflow_usage','V') IS NOT NULL DROP VIEW vw_agent_capability_workflow_usage;
EXEC('CREATE VIEW vw_agent_capability_workflow_usage AS SELECT w.*, c.organization_id, c.capability_code, c.capability_name, c.domain FROM ai_capability_workflow_usage w JOIN ai_capabilities c ON c.id=w.capability_id');
IF OBJECT_ID('vw_agent_capability_provider_models','V') IS NOT NULL DROP VIEW vw_agent_capability_provider_models;
EXEC('CREATE VIEW vw_agent_capability_provider_models AS SELECT p.*, c.organization_id, c.capability_code, c.capability_name, c.domain FROM ai_capability_provider_models p JOIN ai_capabilities c ON c.id=p.capability_id');
IF OBJECT_ID('vw_agent_capability_tools','V') IS NOT NULL DROP VIEW vw_agent_capability_tools;
EXEC('CREATE VIEW vw_agent_capability_tools AS SELECT t.*, c.organization_id, c.capability_code, c.capability_name, c.domain FROM ai_capability_tool_requirements t JOIN ai_capabilities c ON c.id=t.capability_id');
IF OBJECT_ID('vw_agent_capability_memory_rag','V') IS NOT NULL DROP VIEW vw_agent_capability_memory_rag;
EXEC('CREATE VIEW vw_agent_capability_memory_rag AS SELECT m.*, c.organization_id, c.capability_code, c.capability_name, c.domain FROM ai_capability_memory_rag m JOIN ai_capabilities c ON c.id=m.capability_id');
IF OBJECT_ID('vw_agent_capability_validations','V') IS NOT NULL DROP VIEW vw_agent_capability_validations;
EXEC('CREATE VIEW vw_agent_capability_validations AS SELECT v.*, c.organization_id, c.capability_code, c.capability_name, c.domain FROM ai_capability_validations v JOIN ai_capabilities c ON c.id=v.capability_id');
IF OBJECT_ID('vw_agent_capability_tests','V') IS NOT NULL DROP VIEW vw_agent_capability_tests;
EXEC('CREATE VIEW vw_agent_capability_tests AS SELECT t.*, c.organization_id, c.capability_code, c.capability_name, c.domain FROM ai_capability_tests t JOIN ai_capabilities c ON c.id=t.capability_id');
IF OBJECT_ID('vw_agent_capability_overlaps','V') IS NOT NULL DROP VIEW vw_agent_capability_overlaps;
EXEC('CREATE VIEW vw_agent_capability_overlaps AS SELECT * FROM ai_capability_overlaps');
IF OBJECT_ID('vw_agent_capability_recommendations','V') IS NOT NULL DROP VIEW vw_agent_capability_recommendations;
EXEC('CREATE VIEW vw_agent_capability_recommendations AS SELECT r.*, c.capability_code, c.capability_name, c.domain FROM ai_capability_recommendations r LEFT JOIN ai_capabilities c ON c.id=r.capability_id');
IF OBJECT_ID('vw_agent_capability_final_output','V') IS NOT NULL DROP VIEW vw_agent_capability_final_output;
EXEC('CREATE VIEW vw_agent_capability_final_output AS SELECT f.*, c.organization_id, c.capability_code, c.capability_name, c.domain FROM ai_capability_final_output_links f JOIN ai_capabilities c ON c.id=f.capability_id');
